import ctypes
import logging
import os
import struct
import sys
import winreg
import zlib
from ctypes import POINTER, WinDLL, byref, c_int, create_unicode_buffer, sizeof, windll, wintypes
from pathlib import Path
from tkinter import *
from tkinter import ttk
from typing import TYPE_CHECKING, ClassVar, Literal, overload

