//! Typed settings model for reference-compatible CMT settings data.

use serde_json::{Map, Value, json};

const LOG_LEVEL_KEY: &str = "log_level";
const UPDATE_SOURCE_KEY: &str = "update_source";
const SCANNER_OVERVIEW_ISSUES_KEY: &str = "scanner_OverviewIssues";
const SCANNER_ERRORS_KEY: &str = "scanner_Errors";
const SCANNER_WRONG_FORMAT_KEY: &str = "scanner_WrongFormat";
const SCANNER_LOOSE_PREVIS_KEY: &str = "scanner_LoosePrevis";
const SCANNER_JUNK_FILES_KEY: &str = "scanner_JunkFiles";
const SCANNER_PROBLEM_OVERRIDES_KEY: &str = "scanner_ProblemOverrides";
const SCANNER_RACE_SUBGRAPHS_KEY: &str = "scanner_RaceSubgraphs";
const DOWNGRADER_KEEP_BACKUPS_KEY: &str = "downgrader_keep_backups";
const DOWNGRADER_DELETE_DELTAS_KEY: &str = "downgrader_delete_deltas";

const KNOWN_KEYS: [&str; 11] = [
    LOG_LEVEL_KEY,
    UPDATE_SOURCE_KEY,
    SCANNER_OVERVIEW_ISSUES_KEY,
    SCANNER_ERRORS_KEY,
    SCANNER_WRONG_FORMAT_KEY,
    SCANNER_LOOSE_PREVIS_KEY,
    SCANNER_JUNK_FILES_KEY,
    SCANNER_PROBLEM_OVERRIDES_KEY,
    SCANNER_RACE_SUBGRAPHS_KEY,
    DOWNGRADER_KEEP_BACKUPS_KEY,
    DOWNGRADER_DELETE_DELTAS_KEY,
];

/// Top-level application settings persisted in the reference `settings.json`.
///
/// This aggregate keeps domain settings typed while later platform code owns
/// filesystem paths and save/load side effects.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AppSettings {
    /// Minimum log severity persisted with the `log_level` JSON key.
    pub log_level: LogLevel,
    /// Update channel persisted with the `update_source` JSON key.
    pub update_source: UpdateSource,
    /// Scanner toggles persisted as reference-compatible `scanner_*` keys.
    pub scanner: ScannerSettings,
    /// Downgrader toggles persisted as reference-compatible `downgrader_*` keys.
    pub downgrader: DowngraderSettings,
}

impl Default for AppSettings {
    fn default() -> Self {
        Self {
            log_level: LogLevel::Info,
            update_source: UpdateSource::Nexus,
            scanner: ScannerSettings::default(),
            downgrader: DowngraderSettings::default(),
        }
    }
}

impl AppSettings {
    /// Parses and repairs a syntactically valid JSON settings object.
    ///
    /// Malformed JSON and non-object roots are rejected so the platform store can
    /// perform the reference-compatible defaults-only reset required by D-09 and
    /// D-11. Valid objects preserve each valid known key independently and report
    /// diagnostics for keys that need default repair or removal.
    pub fn from_json_str(source: &str) -> Result<SettingsRepairResult, SettingsParseError> {
        let value: Value =
            serde_json::from_str(source).map_err(SettingsParseError::MalformedJson)?;
        let object = value.as_object().ok_or(SettingsParseError::NonObjectRoot)?;
        Ok(Self::apply_json_object(object))
    }

    /// Applies reference-compatible per-key repair semantics to a JSON object.
    ///
    /// Unknown keys are ignored in memory and therefore omitted when the returned
    /// settings are serialized with [`AppSettings::to_json_value`].
    pub fn apply_json_object(object: &Map<String, Value>) -> SettingsRepairResult {
        let mut settings = Self::default();
        let mut diagnostics = Vec::new();

        for key in KNOWN_KEYS {
            if !object.contains_key(key) {
                diagnostics.push(RepairDiagnostic::MissingKey {
                    key: key.to_owned(),
                });
            }
        }

        for (key, value) in object {
            match key.as_str() {
                LOG_LEVEL_KEY => match value.as_str().and_then(LogLevel::from_wire_value) {
                    Some(log_level) => settings.log_level = log_level,
                    None if value.is_string() => {
                        diagnostics.push(RepairDiagnostic::InvalidValue { key: key.clone() })
                    }
                    None => diagnostics.push(RepairDiagnostic::InvalidType { key: key.clone() }),
                },
                UPDATE_SOURCE_KEY => match value.as_str().and_then(UpdateSource::from_wire_value) {
                    Some(update_source) => settings.update_source = update_source,
                    None if value.is_string() => {
                        diagnostics.push(RepairDiagnostic::InvalidValue { key: key.clone() })
                    }
                    None => diagnostics.push(RepairDiagnostic::InvalidType { key: key.clone() }),
                },
                SCANNER_OVERVIEW_ISSUES_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.overview_issues,
                    &mut diagnostics,
                ),
                SCANNER_ERRORS_KEY => {
                    apply_bool(value, key, &mut settings.scanner.errors, &mut diagnostics)
                }
                SCANNER_WRONG_FORMAT_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.wrong_format,
                    &mut diagnostics,
                ),
                SCANNER_LOOSE_PREVIS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.loose_previs,
                    &mut diagnostics,
                ),
                SCANNER_JUNK_FILES_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.junk_files,
                    &mut diagnostics,
                ),
                SCANNER_PROBLEM_OVERRIDES_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.problem_overrides,
                    &mut diagnostics,
                ),
                SCANNER_RACE_SUBGRAPHS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.race_subgraphs,
                    &mut diagnostics,
                ),
                DOWNGRADER_KEEP_BACKUPS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.downgrader.keep_backups,
                    &mut diagnostics,
                ),
                DOWNGRADER_DELETE_DELTAS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.downgrader.delete_deltas,
                    &mut diagnostics,
                ),
                _ => diagnostics.push(RepairDiagnostic::UnknownKey { key: key.clone() }),
            }
        }

        SettingsRepairResult {
            settings,
            diagnostics,
        }
    }

    /// Converts settings into the reference-compatible JSON object shape.
    ///
    /// Keys intentionally preserve the mixed-case scanner names used by
    /// `CMT/src/app_settings.py` so later file IO can resave repaired settings
    /// without introducing Rust-style snake_case key drift.
    pub fn to_json_value(&self) -> Value {
        json!({
            "log_level": self.log_level.as_wire_value(),
            "update_source": self.update_source.as_wire_value(),
            "scanner_OverviewIssues": self.scanner.overview_issues,
            "scanner_Errors": self.scanner.errors,
            "scanner_WrongFormat": self.scanner.wrong_format,
            "scanner_LoosePrevis": self.scanner.loose_previs,
            "scanner_JunkFiles": self.scanner.junk_files,
            "scanner_ProblemOverrides": self.scanner.problem_overrides,
            "scanner_RaceSubgraphs": self.scanner.race_subgraphs,
            "downgrader_keep_backups": self.downgrader.keep_backups,
            "downgrader_delete_deltas": self.downgrader.delete_deltas,
        })
    }
}

fn apply_bool(
    value: &Value,
    key: &str,
    target: &mut bool,
    diagnostics: &mut Vec<RepairDiagnostic>,
) {
    if let Some(value) = value.as_bool() {
        *target = value;
    } else {
        diagnostics.push(RepairDiagnostic::InvalidType {
            key: key.to_owned(),
        });
    }
}

/// Parsed settings plus diagnostics describing any quiet repairs made.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsRepairResult {
    /// Typed settings after valid values were applied and invalid values defaulted.
    pub settings: AppSettings,
    /// Diagnostics for test assertions and later logging; values are deliberately omitted.
    pub diagnostics: Vec<RepairDiagnostic>,
}

/// Non-sensitive diagnostic for a single settings repair action.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RepairDiagnostic {
    /// A known reference key was absent and retained its default value.
    MissingKey { key: String },
    /// A known enum/string key had an unsupported string value.
    InvalidValue { key: String },
    /// A known key had the wrong JSON type.
    InvalidType { key: String },
    /// An unknown key was ignored and will be omitted on resave.
    UnknownKey { key: String },
}

/// Parse errors that require the platform store to reset settings to defaults.
#[derive(Debug)]
pub enum SettingsParseError {
    /// JSON parsing failed before a trustworthy object could be inspected.
    MalformedJson(serde_json::Error),
    /// The parsed JSON root was not an object.
    NonObjectRoot,
}

/// Reference log level values accepted by the persisted settings contract.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LogLevel {
    /// Extra-verbose log output.
    Debug,
    /// Reference default log level.
    Info,
    /// Warning-and-above log output accepted by the reference settings schema.
    Warning,
    /// Error-only log output.
    Error,
}

impl LogLevel {
    /// Returns the exact string persisted for this log level in `settings.json`.
    pub const fn as_wire_value(self) -> &'static str {
        match self {
            Self::Debug => "DEBUG",
            Self::Info => "INFO",
            Self::Warning => "WARNING",
            Self::Error => "ERROR",
        }
    }

    /// Converts a persisted log-level string into the typed value when supported.
    pub fn from_wire_value(value: &str) -> Option<Self> {
        match value {
            "DEBUG" => Some(Self::Debug),
            "INFO" => Some(Self::Info),
            "WARNING" => Some(Self::Warning),
            "ERROR" => Some(Self::Error),
            _ => None,
        }
    }
}

/// Update channel persisted for later update-check behavior.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum UpdateSource {
    /// Check both GitHub and Nexus Mods.
    Both,
    /// Check GitHub only.
    Github,
    /// Check Nexus Mods only.
    Nexus,
    /// Do not check for updates.
    None,
}

impl UpdateSource {
    /// Returns the exact string persisted for this update source in `settings.json`.
    pub const fn as_wire_value(self) -> &'static str {
        match self {
            Self::Both => "both",
            Self::Github => "github",
            Self::Nexus => "nexus",
            Self::None => "none",
        }
    }

    /// Converts a persisted update-source string into the typed value when supported.
    pub fn from_wire_value(value: &str) -> Option<Self> {
        match value {
            "both" => Some(Self::Both),
            "github" => Some(Self::Github),
            "nexus" => Some(Self::Nexus),
            "none" => Some(Self::None),
            _ => None,
        }
    }
}

/// Scanner category toggles persisted by the Settings model.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScannerSettings {
    /// Enables overview issue checks.
    pub overview_issues: bool,
    /// Enables generic error checks.
    pub errors: bool,
    /// Enables wrong file format checks.
    pub wrong_format: bool,
    /// Enables loose previs checks.
    pub loose_previs: bool,
    /// Enables junk file checks.
    pub junk_files: bool,
    /// Enables problematic override checks.
    pub problem_overrides: bool,
    /// Enables race subgraph checks.
    pub race_subgraphs: bool,
}

impl Default for ScannerSettings {
    fn default() -> Self {
        Self {
            overview_issues: true,
            errors: true,
            wrong_format: true,
            loose_previs: true,
            junk_files: true,
            problem_overrides: true,
            race_subgraphs: true,
        }
    }
}

/// Downgrader workflow preferences persisted by the Settings model.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DowngraderSettings {
    /// Keeps backups when later downgrader operations modify files.
    pub keep_backups: bool,
    /// Deletes delta files after later downgrader operations use them.
    pub delete_deltas: bool,
}

impl Default for DowngraderSettings {
    fn default() -> Self {
        Self {
            keep_backups: true,
            delete_deltas: true,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    const REFERENCE_KEYS: [&str; 11] = [
        "log_level",
        "update_source",
        "scanner_OverviewIssues",
        "scanner_Errors",
        "scanner_WrongFormat",
        "scanner_LoosePrevis",
        "scanner_JunkFiles",
        "scanner_ProblemOverrides",
        "scanner_RaceSubgraphs",
        "downgrader_keep_backups",
        "downgrader_delete_deltas",
    ];

    #[test]
    fn settings_missing_file_defaults() {
        let settings = AppSettings::default();

        assert_eq!(settings.log_level, LogLevel::Info);
        assert_eq!(settings.update_source, UpdateSource::Nexus);
        assert!(settings.downgrader.keep_backups);
        assert!(settings.downgrader.delete_deltas);
    }

    #[test]
    fn settings_persist_reference_keys() {
        let json = AppSettings::default().to_json_value();
        let object = json
            .as_object()
            .expect("settings should serialize as object");

        let mut keys: Vec<&str> = object.keys().map(String::as_str).collect();
        keys.sort_unstable();
        let mut expected_keys = REFERENCE_KEYS.to_vec();
        expected_keys.sort_unstable();
        assert_eq!(keys, expected_keys);

        assert_eq!(json["log_level"], "INFO");
        assert_eq!(LogLevel::Debug.as_wire_value(), "DEBUG");
        assert_eq!(LogLevel::Info.as_wire_value(), "INFO");
        assert_eq!(LogLevel::Warning.as_wire_value(), "WARNING");
        assert_eq!(LogLevel::Error.as_wire_value(), "ERROR");
        assert_eq!(json["update_source"], "nexus");
        assert!(!object.contains_key("scanner_overview_issues"));
        assert!(!object.contains_key("scanner_wrong_format"));
    }

    #[test]
    fn scanner_settings_defaults_enabled() {
        let scanner = ScannerSettings::default();

        assert!(scanner.overview_issues);
        assert!(scanner.errors);
        assert!(scanner.wrong_format);
        assert!(scanner.loose_previs);
        assert!(scanner.junk_files);
        assert!(scanner.problem_overrides);
        assert!(scanner.race_subgraphs);
    }

    #[test]
    fn settings_repair() {
        assert!(AppSettings::from_json_str("{ not json").is_err());
        assert!(AppSettings::from_json_str("[]").is_err());

        let repaired = AppSettings::from_json_str(
            r#"{
                "log_level": "DEBUG",
                "update_source": "bogus",
                "scanner_OverviewIssues": false,
                "scanner_Errors": "yes",
                "scanner_WrongFormat": false,
                "scanner_LoosePrevis": false,
                "scanner_JunkFiles": false,
                "scanner_ProblemOverrides": false,
                "scanner_RaceSubgraphs": false,
                "downgrader_keep_backups": false,
                "unknown_setting": true
            }"#,
        )
        .expect("syntactically valid JSON object should repair per key");

        assert_eq!(repaired.settings.log_level, LogLevel::Debug);
        assert_eq!(repaired.settings.update_source, UpdateSource::Nexus);
        assert!(!repaired.settings.scanner.overview_issues);
        assert!(repaired.settings.scanner.errors);
        assert!(!repaired.settings.scanner.wrong_format);
        assert!(!repaired.settings.scanner.loose_previs);
        assert!(!repaired.settings.scanner.junk_files);
        assert!(!repaired.settings.scanner.problem_overrides);
        assert!(!repaired.settings.scanner.race_subgraphs);
        assert!(!repaired.settings.downgrader.keep_backups);
        assert!(repaired.settings.downgrader.delete_deltas);

        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::InvalidValue { key } if key == "update_source")
        }));
        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::InvalidType { key } if key == "scanner_Errors")
        }));
        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::MissingKey { key } if key == "downgrader_delete_deltas")
        }));
        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::UnknownKey { key } if key == "unknown_setting")
        }));

        let repaired_json = repaired.settings.to_json_value();
        let repaired_object = repaired_json
            .as_object()
            .expect("repaired settings should serialize as object");
        assert!(!repaired_object.contains_key("unknown_setting"));

        let warning = AppSettings::from_json_str(r#"{"log_level":"WARNING"}"#)
            .expect("reference-valid WARNING log_level should load");
        assert_eq!(warning.settings.log_level, LogLevel::Warning);
    }
}

//! Fakeable filesystem adapter contracts for discovery and scan code.
//!
//! The real adapter performs ordinary filesystem reads and deterministic
//! directory traversal. Callers should depend on [`Filesystem`] so tests can use
//! in-memory fakes instead of a real Fallout 4 installation tree.

use std::{
    fs,
    io::Read,
    path::{Path, PathBuf},
};

use walkdir::WalkDir;

use crate::platform::{PlatformError, PlatformOperation, PlatformResult};

/// File type information exposed by filesystem adapters.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum FileType {
    /// Regular file.
    File,
    /// Directory.
    Directory,
    /// Symbolic link.
    Symlink,
    /// Any platform-specific file type not otherwise classified.
    Other,
}

impl FileType {
    fn from_std(file_type: fs::FileType) -> Self {
        if file_type.is_file() {
            Self::File
        } else if file_type.is_dir() {
            Self::Directory
        } else if file_type.is_symlink() {
            Self::Symlink
        } else {
            Self::Other
        }
    }
}

/// Metadata returned for a single filesystem path.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct FileMetadata {
    /// Classified file type.
    pub file_type: FileType,
    /// Byte length reported by the OS for files and other entries.
    pub len: u64,
}

impl FileMetadata {
    /// Returns true when this metadata describes a regular file.
    pub const fn is_file(&self) -> bool {
        matches!(self.file_type, FileType::File)
    }

    /// Returns true when this metadata describes a directory.
    pub const fn is_dir(&self) -> bool {
        matches!(self.file_type, FileType::Directory)
    }
}

/// Directory entry returned by direct and recursive enumeration.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct DirectoryEntry {
    /// Full path to the entry as supplied by the adapter.
    pub path: PathBuf,
    /// Classified file type for the entry.
    pub file_type: FileType,
}

impl DirectoryEntry {
    /// Creates a typed directory entry.
    pub fn new(path: impl Into<PathBuf>, file_type: FileType) -> Self {
        Self {
            path: path.into(),
            file_type,
        }
    }
}

/// Filesystem operations needed by discovery, scan, parser, and patch code.
pub trait Filesystem {
    /// Reads metadata for a path.
    fn metadata(&self, path: &Path) -> PlatformResult<FileMetadata>;

    /// Returns true when a path exists, false for not-found, and errors for unsafe ambiguity.
    fn exists(&self, path: &Path) -> PlatformResult<bool> {
        match self.metadata(path) {
            Ok(_) => Ok(true),
            Err(error) if error.kind == crate::platform::PlatformErrorKind::NotFound => Ok(false),
            Err(error) => Err(error),
        }
    }

    /// Returns true when a path is a regular file.
    fn is_file(&self, path: &Path) -> PlatformResult<bool> {
        match self.metadata(path) {
            Ok(metadata) => Ok(metadata.is_file()),
            Err(error) if error.kind == crate::platform::PlatformErrorKind::NotFound => Ok(false),
            Err(error) => Err(error),
        }
    }

    /// Returns true when a path is a directory.
    fn is_dir(&self, path: &Path) -> PlatformResult<bool> {
        match self.metadata(path) {
            Ok(metadata) => Ok(metadata.is_dir()),
            Err(error) if error.kind == crate::platform::PlatformErrorKind::NotFound => Ok(false),
            Err(error) => Err(error),
        }
    }

    /// Reads a whole file as bytes.
    fn read_bytes(&self, path: &Path) -> PlatformResult<Vec<u8>>;

    /// Reads at most `max_len` bytes from the start of a file.
    ///
    /// Real adapters should override this to avoid full-file reads for parser
    /// probes. The default keeps existing fakes small while preserving the same
    /// error behavior as [`Filesystem::read_bytes`].
    fn read_prefix(&self, path: &Path, max_len: usize) -> PlatformResult<Vec<u8>> {
        let mut bytes = self.read_bytes(path)?;
        bytes.truncate(max_len);
        Ok(bytes)
    }

    /// Reads a whole UTF-8 text file.
    fn read_to_string(&self, path: &Path) -> PlatformResult<String>;

    /// Lists direct children of a directory in deterministic path order.
    fn read_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>>;

    /// Recursively lists a directory tree in deterministic path order.
    fn walk_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>>;
}

/// Production filesystem adapter backed by `std::fs` and deterministic `walkdir` traversal.
#[derive(Debug, Default, Clone, Copy)]
pub struct RealFilesystem;

impl RealFilesystem {
    /// Creates the production filesystem adapter without touching the filesystem.
    pub const fn new() -> Self {
        Self
    }
}

impl Filesystem for RealFilesystem {
    fn metadata(&self, path: &Path) -> PlatformResult<FileMetadata> {
        fs::metadata(path)
            .map(|metadata| FileMetadata {
                file_type: FileType::from_std(metadata.file_type()),
                len: metadata.len(),
            })
            .map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadMetadata,
                    path.display().to_string(),
                    &error,
                )
            })
    }

    fn read_bytes(&self, path: &Path) -> PlatformResult<Vec<u8>> {
        fs::read(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadFile,
                path.display().to_string(),
                &error,
            )
        })
    }

    fn read_prefix(&self, path: &Path, max_len: usize) -> PlatformResult<Vec<u8>> {
        let mut file = fs::File::open(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadFile,
                path.display().to_string(),
                &error,
            )
        })?;
        let mut bytes = Vec::with_capacity(max_len);
        file.by_ref()
            .take(max_len as u64)
            .read_to_end(&mut bytes)
            .map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    &error,
                )
            })?;
        Ok(bytes)
    }

    fn read_to_string(&self, path: &Path) -> PlatformResult<String> {
        fs::read_to_string(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadFile,
                path.display().to_string(),
                &error,
            )
        })
    }

    fn read_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
        let mut entries = Vec::new();
        let iterator = fs::read_dir(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadDirectory,
                path.display().to_string(),
                &error,
            )
        })?;

        for entry in iterator {
            let entry = entry.map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadDirectory,
                    path.display().to_string(),
                    &error,
                )
            })?;
            let entry_path = entry.path();
            let file_type = entry.file_type().map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadMetadata,
                    entry_path.display().to_string(),
                    &error,
                )
            })?;
            entries.push(DirectoryEntry::new(
                entry_path,
                FileType::from_std(file_type),
            ));
        }

        entries.sort_by(|left, right| left.path.cmp(&right.path));
        Ok(entries)
    }

    fn walk_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
        let mut entries = Vec::new();
        for entry in WalkDir::new(path).sort_by_file_name() {
            let entry = entry.map_err(|error| walkdir_error(path, error))?;
            let file_type = entry.file_type();
            let file_type = if file_type.is_file() {
                FileType::File
            } else if file_type.is_dir() {
                FileType::Directory
            } else if file_type.is_symlink() {
                FileType::Symlink
            } else {
                FileType::Other
            };
            entries.push(DirectoryEntry::new(entry.path().to_path_buf(), file_type));
        }
        Ok(entries)
    }
}

fn walkdir_error(root: &Path, error: walkdir::Error) -> PlatformError {
    let target = error.path().unwrap_or(root).display().to_string();
    if let Some(io_error) = error.io_error() {
        PlatformError::from_io(PlatformOperation::WalkDirectory, target, io_error)
    } else {
        PlatformError::command_failed(PlatformOperation::WalkDirectory, target, error.to_string())
    }
}

#[cfg(test)]
mod tests {
    use std::collections::{BTreeMap, BTreeSet};

    use crate::platform::{PlatformErrorKind, PlatformOperation};

    use super::*;

    #[derive(Debug, Clone, PartialEq, Eq)]
    enum FakeNode {
        File(Vec<u8>),
        Directory,
        Denied,
    }

    #[derive(Debug, Default)]
    struct FakeFilesystem {
        nodes: BTreeMap<PathBuf, FakeNode>,
    }

    impl FakeFilesystem {
        fn with_file(mut self, path: &str, bytes: impl Into<Vec<u8>>) -> Self {
            self.nodes
                .insert(PathBuf::from(path), FakeNode::File(bytes.into()));
            self
        }

        fn with_dir(mut self, path: &str) -> Self {
            self.nodes.insert(PathBuf::from(path), FakeNode::Directory);
            self
        }

        fn with_denied(mut self, path: &str) -> Self {
            self.nodes.insert(PathBuf::from(path), FakeNode::Denied);
            self
        }

        fn node(&self, path: &Path, operation: PlatformOperation) -> PlatformResult<&FakeNode> {
            match self.nodes.get(path) {
                Some(FakeNode::Denied) => Err(PlatformError::new(
                    operation,
                    path.display().to_string(),
                    PlatformErrorKind::PermissionDenied,
                    format!(
                        "{} target could not be accessed because permission was denied.",
                        operation.label()
                    ),
                )),
                Some(node) => Ok(node),
                None => Err(PlatformError::new(
                    operation,
                    path.display().to_string(),
                    PlatformErrorKind::NotFound,
                    format!("{} target was not found.", operation.label()),
                )),
            }
        }
    }

    impl Filesystem for FakeFilesystem {
        fn metadata(&self, path: &Path) -> PlatformResult<FileMetadata> {
            let node = self.node(path, PlatformOperation::ReadMetadata)?;
            let file_type = match node {
                FakeNode::File(bytes) => {
                    return Ok(FileMetadata {
                        file_type: FileType::File,
                        len: bytes.len() as u64,
                    });
                }
                FakeNode::Directory => FileType::Directory,
                FakeNode::Denied => unreachable!("denied nodes return before classification"),
            };
            Ok(FileMetadata { file_type, len: 0 })
        }

        fn read_bytes(&self, path: &Path) -> PlatformResult<Vec<u8>> {
            match self.node(path, PlatformOperation::ReadFile)? {
                FakeNode::File(bytes) => Ok(bytes.clone()),
                FakeNode::Directory => Err(PlatformError::new(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    PlatformErrorKind::InvalidInput,
                    "File read target is invalid.",
                )),
                FakeNode::Denied => unreachable!("denied nodes return before reads"),
            }
        }

        fn read_to_string(&self, path: &Path) -> PlatformResult<String> {
            String::from_utf8(self.read_bytes(path)?).map_err(|error| {
                PlatformError::parse_error(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    error.to_string(),
                )
            })
        }

        fn read_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
            self.node(path, PlatformOperation::ReadDirectory)?;
            let mut entries = Vec::new();
            for (candidate, node) in &self.nodes {
                if candidate.parent() == Some(path) {
                    let file_type = match node {
                        FakeNode::File(_) => FileType::File,
                        FakeNode::Directory => FileType::Directory,
                        FakeNode::Denied => FileType::Other,
                    };
                    entries.push(DirectoryEntry::new(candidate.clone(), file_type));
                }
            }
            Ok(entries)
        }

        fn walk_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
            self.node(path, PlatformOperation::WalkDirectory)?;
            let mut entries = Vec::new();
            for (candidate, node) in &self.nodes {
                if candidate == path || candidate.starts_with(path) {
                    let file_type = match node {
                        FakeNode::File(_) => FileType::File,
                        FakeNode::Directory => FileType::Directory,
                        FakeNode::Denied => FileType::Other,
                    };
                    entries.push(DirectoryEntry::new(candidate.clone(), file_type));
                }
            }
            Ok(entries)
        }
    }

    fn collect_files(fs: &dyn Filesystem, root: &Path) -> PlatformResult<BTreeSet<PathBuf>> {
        Ok(fs
            .walk_dir(root)?
            .into_iter()
            .filter(|entry| entry.file_type == FileType::File)
            .map(|entry| entry.path)
            .collect())
    }

    #[test]
    fn fake_filesystem_drives_scan_style_directory_inputs() {
        let fs = FakeFilesystem::default()
            .with_dir("Data")
            .with_file("Data/Fallout4.esm", b"plugin".to_vec())
            .with_file("Data/Fallout4 - Main.ba2", b"archive".to_vec())
            .with_dir("Data/F4SE");

        let files = collect_files(&fs, Path::new("Data")).expect("fake traversal should work");

        assert_eq!(
            files,
            BTreeSet::from([
                PathBuf::from("Data/Fallout4 - Main.ba2"),
                PathBuf::from("Data/Fallout4.esm"),
            ])
        );
        assert!(fs.is_dir(Path::new("Data")).expect("fake dir metadata"));
        assert!(
            fs.is_file(Path::new("Data/Fallout4.esm"))
                .expect("fake file metadata")
        );
        assert_eq!(
            fs.read_to_string(Path::new("Data/Fallout4.esm"))
                .expect("fake text read"),
            "plugin"
        );
    }

    #[test]
    fn fake_filesystem_surfaces_typed_failure_without_real_paths() {
        let fs = FakeFilesystem::default()
            .with_dir("Data")
            .with_denied("Data/Private.ba2");

        let error = fs
            .metadata(Path::new("Data/Private.ba2"))
            .expect_err("denied fake path should fail");

        assert_eq!(error.operation, PlatformOperation::ReadMetadata);
        assert_eq!(error.kind, PlatformErrorKind::PermissionDenied);
        assert_eq!(
            error.user_message(),
            "Filesystem metadata read target could not be accessed because permission was denied."
        );
    }

    #[test]
    fn real_filesystem_missing_file_maps_to_typed_not_found() {
        let fs = RealFilesystem::new();
        let missing = Path::new("definitely-not-a-cmt-rs-platform-test-file.nope");

        let error = fs
            .read_bytes(missing)
            .expect_err("missing file should produce typed failure");

        assert_eq!(error.kind, PlatformErrorKind::NotFound);
        assert_eq!(error.operation, PlatformOperation::ReadFile);
        assert_eq!(error.user_message(), "File read target was not found.");
    }
}

//! Typed worker event contracts for long-running background operations.
//!
//! The types in this module are owned, `Send`-friendly values that can cross a
//! background-worker boundary before a UI-specific handoff layer decides how to
//! display them. They intentionally avoid Slint handles, models, and borrowed
//! filesystem state.

use std::{
    fmt,
    sync::{
        Arc,
        atomic::{AtomicBool, Ordering},
    },
};

use crate::{
    domain::{
        autofix::AutoFixCompletion,
        f4se::F4seScanSnapshot,
        overview::{
            OverviewActionError, OverviewDeferredActionKind, OverviewSnapshot, UpdateBannerState,
        },
        scanner::{ScannerActionFeedback, ScannerScanSnapshot},
    },
    platform::{
        PlatformError, PlatformErrorKind, PlatformOperation,
        desktop::{DesktopActionOutcome, DesktopActionResult},
    },
    services::tools::{AboutActionFeedback, ToolsActionFeedback},
};

/// Stable identity for one background task.
#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct WorkerTaskId(String);

impl WorkerTaskId {
    /// Creates a task id from a caller-supplied stable identifier.
    pub fn new(id: impl Into<String>) -> Self {
        Self(id.into())
    }

    /// Returns the task id as a borrowed string for logs and diagnostics.
    pub fn as_str(&self) -> &str {
        &self.0
    }
}

impl From<&str> for WorkerTaskId {
    fn from(value: &str) -> Self {
        Self::new(value)
    }
}

impl From<String> for WorkerTaskId {
    fn from(value: String) -> Self {
        Self::new(value)
    }
}

impl fmt::Display for WorkerTaskId {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.as_str())
    }
}

/// High-level category for a background task.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum WorkerTaskKind {
    /// Complete Overview refresh, update-check, or Overview-specific orchestration work.
    Overview,
    /// Fallout 4 installation, manager, registry, process, or system discovery.
    Discovery,
    /// Scanner traversal, parsing, or classification work.
    Scan,
    /// Archive or file patching work.
    Patch,
    /// Network download or update retrieval work.
    Download,
    /// External process execution or monitoring work.
    ExternalProcess,
    /// Desktop handoff such as opening a URL or path.
    DesktopAction,
    /// Generic typed work whose concrete category is not important to the UI.
    Generic,
    /// Unknown work kind retained for forward-compatible handoff.
    Unknown,
}

impl WorkerTaskKind {
    /// Returns a stable label suitable for structured logs and tests.
    pub const fn label(self) -> &'static str {
        match self {
            Self::Overview => "overview",
            Self::Discovery => "discovery",
            Self::Scan => "scan",
            Self::Patch => "patch",
            Self::Download => "download",
            Self::ExternalProcess => "external-process",
            Self::DesktopAction => "desktop-action",
            Self::Generic => "generic",
            Self::Unknown => "unknown",
        }
    }
}

impl fmt::Display for WorkerTaskKind {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.label())
    }
}

/// Shared task metadata attached to every worker event envelope.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct WorkerTask {
    /// Stable task identity chosen by the service that scheduled the work.
    pub id: WorkerTaskId,
    /// High-level work category used by status surfaces.
    pub kind: WorkerTaskKind,
    /// Optional short human-readable label for display surfaces.
    pub label: Option<String>,
}

impl WorkerTask {
    /// Creates a worker task from an id and work kind.
    pub fn new(id: impl Into<WorkerTaskId>, kind: WorkerTaskKind) -> Self {
        Self {
            id: id.into(),
            kind,
            label: None,
        }
    }

    /// Adds a short display label while preserving the stable id.
    pub fn with_label(mut self, label: impl Into<String>) -> Self {
        self.label = Some(label.into());
        self
    }
}

/// Lifecycle/status value for a worker event envelope.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum WorkerTaskStatus {
    /// Task is queued but not running yet.
    Queued,
    /// Task is executing on a worker thread.
    Running,
    /// Task emitted partial progress.
    Progress,
    /// Cancellation was requested by a caller or UI control.
    CancellationRequested,
    /// Worker observed the cancellation request and acknowledged it.
    CancellationAcknowledged,
    /// Task completed successfully.
    Completed,
    /// Task completed with cancellation as its final state.
    Cancelled,
    /// Task completed with a typed failure.
    Failed,
}

impl WorkerTaskStatus {
    /// Returns a stable label suitable for structured logs and tests.
    pub const fn label(self) -> &'static str {
        match self {
            Self::Queued => "queued",
            Self::Running => "running",
            Self::Progress => "progress",
            Self::CancellationRequested => "cancellation-requested",
            Self::CancellationAcknowledged => "cancellation-acknowledged",
            Self::Completed => "completed",
            Self::Cancelled => "cancelled",
            Self::Failed => "failed",
        }
    }

    /// Returns true when no further events are expected for the task.
    pub const fn is_terminal(self) -> bool {
        matches!(self, Self::Completed | Self::Cancelled | Self::Failed)
    }
}

impl fmt::Display for WorkerTaskStatus {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.label())
    }
}

/// Shared envelope emitted by every background worker.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerEvent {
    /// Stable task identity and high-level kind metadata.
    pub task: WorkerTask,
    /// Current lifecycle/status for this event.
    pub status: WorkerTaskStatus,
    /// Typed event-specific payload.
    pub payload: WorkerPayload,
}

impl WorkerEvent {
    /// Creates a typed worker event envelope.
    pub fn new(task: WorkerTask, status: WorkerTaskStatus, payload: WorkerPayload) -> Self {
        Self {
            task,
            status,
            payload,
        }
    }

    /// Creates a running lifecycle event.
    pub fn running(task: WorkerTask) -> Self {
        Self::new(task, WorkerTaskStatus::Running, WorkerPayload::None)
    }

    /// Creates a progress event with optional text and counts.
    pub fn progress(task: WorkerTask, progress: WorkerProgress) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::Progress,
            WorkerPayload::Progress(progress),
        )
    }

    /// Creates a successful completion event.
    pub fn completed(task: WorkerTask, payload: WorkerPayload) -> Self {
        Self::new(task, WorkerTaskStatus::Completed, payload)
    }

    /// Creates a typed failure event.
    pub fn failed(task: WorkerTask, failure: WorkerFailure) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::Failed,
            WorkerPayload::Error(failure),
        )
    }

    /// Creates a cancellation-request event.
    pub fn cancellation_requested(task: WorkerTask, cancellation: WorkerCancellation) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::CancellationRequested,
            WorkerPayload::Cancellation(cancellation),
        )
    }

    /// Creates a cancellation-acknowledgement event.
    pub fn cancellation_acknowledged(task: WorkerTask, cancellation: WorkerCancellation) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::CancellationAcknowledged,
            WorkerPayload::Cancellation(cancellation),
        )
    }

    /// Creates the final cancelled completion event.
    pub fn cancelled(task: WorkerTask, cancellation: WorkerCancellation) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::Cancelled,
            WorkerPayload::Cancellation(cancellation),
        )
    }
}

/// Optional progress text and counts for a worker task.
#[derive(Debug, Default, Clone, PartialEq, Eq, Hash)]
pub struct WorkerProgress {
    /// Optional safe text for status labels or logs.
    pub message: Option<String>,
    /// Optional completed item count.
    pub current: Option<u64>,
    /// Optional total item count when it is cheap and meaningful to know.
    pub total: Option<u64>,
}

impl WorkerProgress {
    /// Creates an empty progress value with no text or counts.
    pub fn new() -> Self {
        Self::default()
    }

    /// Adds safe human-readable progress text.
    pub fn with_message(mut self, message: impl Into<String>) -> Self {
        self.message = Some(message.into());
        self
    }

    /// Adds optional current and total counts without implying percentages or ETA.
    pub const fn with_counts(mut self, current: Option<u64>, total: Option<u64>) -> Self {
        self.current = current;
        self.total = total;
        self
    }

    /// Returns true when this progress value has no text or counts.
    pub const fn is_empty(&self) -> bool {
        self.message.is_none() && self.current.is_none() && self.total.is_none()
    }
}

/// Safe text payload used by task-specific message variants.
