    use crate::workers::events::{WorkerMessage, WorkerTaskKind};

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn blocking_facade_runs_work_off_calling_thread_and_records_events() {
        let runtime = WorkerRuntime::new();
        let sink = RecordingEventSink::new();
        let calling_thread = std::thread::current().id();
        let worker_thread: Arc<Mutex<Option<ThreadId>>> = Arc::new(Mutex::new(None));
        let worker_thread_for_task = Arc::clone(&worker_thread);
        let task = WorkerTask::new("scan-data", WorkerTaskKind::Scan);

        let handle = runtime
            .spawn_blocking_task(task, sink.clone(), move |context| {
                *worker_thread_for_task
                    .lock()
                    .expect("worker thread id should be writable") =
                    Some(std::thread::current().id());
                context
                    .emit_progress(
                        WorkerProgress::new()
                            .with_message("Scanning Data folder")
                            .with_counts(Some(1), Some(2)),
                    )
                    .expect("progress should be recorded");
                Ok(WorkerTaskOutcome::Completed(WorkerPayload::Scan(
                    WorkerMessage::new("Scan complete."),
                )))
            })
            .expect("active Tokio runtime should schedule blocking work");

        handle.join().await.expect("worker task should join");

        let actual_worker_thread = worker_thread
            .lock()
            .expect("worker thread id should be readable")
            .expect("worker thread id should be recorded");
        assert_ne!(actual_worker_thread, calling_thread);

        let events = sink.events().expect("recorded events should be readable");
        assert_eq!(
            events.first().map(|event| event.status),
            Some(WorkerTaskStatus::Running)
        );
        assert!(events.iter().any(|event| matches!(
            &event.payload,
            WorkerPayload::Progress(WorkerProgress {
                current: Some(1),
                total: Some(2),
                ..
            })
        )));
        assert_eq!(
            events.last().map(|event| event.status),
            Some(WorkerTaskStatus::Completed)
        );
        assert!(matches!(
            events.last().map(|event| &event.payload),
            Some(WorkerPayload::Scan(_))
        ));
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn cancellation_request_acknowledgement_and_final_cancelled_flow_through_facade() {
        let runtime = WorkerRuntime::new();
        let sink = RecordingEventSink::new();
        let task = WorkerTask::new("download-cancel", WorkerTaskKind::Download);

        let handle = runtime
            .spawn_blocking_task(task, sink.clone(), move |context| {
                while !context.is_cancellation_requested() {
                    std::thread::sleep(Duration::from_millis(1));
                }
                context
                    .acknowledge_cancellation(WorkerCancellation::with_message("Worker stopping."))
                    .expect("acknowledgement should be recorded");
                Ok(WorkerTaskOutcome::Cancelled(
                    WorkerCancellation::with_message("Download stopped."),
                ))
            })
            .expect("active Tokio runtime should schedule blocking work");

        handle
            .request_cancellation(WorkerCancellation::with_message("User requested stop."))
            .expect("cancellation request should be recorded");
        handle.join().await.expect("cancelled task should join");

        let statuses = sink
            .events()
            .expect("recorded events should be readable")
            .into_iter()
            .map(|event| event.status)
            .collect::<Vec<_>>();

        assert!(statuses.contains(&WorkerTaskStatus::CancellationRequested));
        assert!(statuses.contains(&WorkerTaskStatus::CancellationAcknowledged));
        assert!(statuses.contains(&WorkerTaskStatus::Cancelled));
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn worker_failures_emit_safe_failure_events() {
        let runtime = WorkerRuntime::new();
        let sink = RecordingEventSink::new();
        let task = WorkerTask::new("patch-failure", WorkerTaskKind::Patch);

        let handle = runtime
            .spawn_blocking_task(task, sink.clone(), |_context| {
                Err(WorkerFailure::new("Patch failed.").with_diagnostic("raw diagnostic detail"))
            })
            .expect("active Tokio runtime should schedule blocking work");

        handle.join().await.expect("failed task should still join");

        let events = sink.events().expect("recorded events should be readable");
        let failed = events
            .iter()
            .find(|event| event.status == WorkerTaskStatus::Failed)
            .expect("failure event should be emitted");

        match &failed.payload {
            WorkerPayload::Error(failure) => {
                assert_eq!(failure.safe_message(), "Patch failed.");
                assert_eq!(failure.diagnostic(), Some("raw diagnostic detail"));
            }
            other => panic!("expected error payload, got {other:?}"),
        }
    }

    #[test]
    fn spawning_without_tokio_runtime_returns_typed_error() {
        let runtime = WorkerRuntime::new();
        let sink = RecordingEventSink::new();
        let task = WorkerTask::new("no-runtime", WorkerTaskKind::Generic);

        let error = match runtime.spawn_blocking_task(task, sink, |_context| {
            Ok(WorkerTaskOutcome::Completed(WorkerPayload::None))
        }) {
            Ok(_) => panic!("spawning without an active Tokio runtime should fail safely"),
            Err(error) => error,
        };

        assert_eq!(
            error,
            WorkerSpawnError::NoActiveRuntime {
                task_id: WorkerTaskId::new("no-runtime"),
            }
        );
    }
}

use std::io;

use crate::{
    domain::settings::{AppSettings, LogLevel, ScannerSettings, UpdateSource},
    platform::settings_store::{AssetResolver, SettingsStore},
};

/// Result of persisting Scanner toggles at Scan Game start.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScannerSettingsSaveResult {
    /// Scanner settings snapshot Slint should display after the save attempt.
    pub visible_settings: ScannerSettings,
    /// True when the candidate scanner settings were successfully persisted.
    pub saved: bool,
}

impl ScannerSettingsSaveResult {
    /// Returns true when callers may schedule a scan with the visible settings snapshot.
    pub const fn should_schedule_scan(&self) -> bool {
        self.saved
    }
}

/// Coordinates Settings-tab UI selections with persisted application settings.
///
/// The controller keeps the last successfully persisted settings snapshot so a
/// failed immediate-save radio change can return the previous value for Slint to
/// display. It does not reconfigure runtime logging; log-level selections only
/// update the persisted `settings.json` value in this phase.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsController<R> {
    store: SettingsStore<R>,
    last_persisted: AppSettings,
}

impl<R: AssetResolver> SettingsController<R> {
    /// Loads settings through the provided store and initializes UI-facing state.
    ///
    /// Any repairs performed by the settings store are reflected in the initial
    /// snapshot. Reference-valid persisted values, including `WARNING`, are
    /// preserved and mapped onto their displayed radio choices.
    pub fn load(store: SettingsStore<R>) -> io::Result<Self> {
        let loaded = store.load()?;

        Ok(Self::from_settings(store, loaded.settings))
    }

    /// Creates a controller around a known settings snapshot without loading from disk.
    ///
    /// This is used as a startup fallback when the production store cannot load or
    /// create `settings.json`; subsequent selections still attempt to save through
    /// the same store and revert to this snapshot if persistence continues to fail.
    pub fn from_settings(store: SettingsStore<R>, settings: AppSettings) -> Self {
        Self {
            store,
            last_persisted: settings,
        }
    }

    /// Returns a read-only snapshot of the last successfully persisted settings.
    pub fn current_settings(&self) -> &AppSettings {
        &self.last_persisted
    }

    /// Returns the last successfully persisted scanner settings.
    pub fn current_scanner_settings(&self) -> &ScannerSettings {
        &self.last_persisted.scanner
    }

    /// Persists scanner settings when the Scanner tab starts `Scan Game`.
    ///
    /// Individual Scanner checkbox toggles are transient controller state. They
    /// are intentionally not written by this Settings controller until scan
    /// start; if the write fails, the previous persisted scanner settings are
    /// returned so Slint can revert the visible checkboxes and skip scheduling
    /// a scan with unpersisted state.
    pub fn save_scanner_settings_for_scan(
        &mut self,
        scanner: ScannerSettings,
    ) -> ScannerSettingsSaveResult {
        let mut candidate = self.last_persisted.clone();
        candidate.scanner = scanner;

        match self.store.save(&candidate) {
            Ok(()) => {
                self.last_persisted = candidate;
                tracing::info!(
                    event = "scanner-settings-save-succeeded",
                    "Scanner settings persisted at scan start"
                );
                ScannerSettingsSaveResult {
                    visible_settings: self.last_persisted.scanner.clone(),
                    saved: true,
                }
            }
            Err(error) => {
                tracing::error!(
                    event = "scanner-settings-save-failed",
                    path = %self.store.settings_path().display(),
                    %error,
                    "Scanner settings failed to save at scan start; reverting visible toggles"
                );
                ScannerSettingsSaveResult {
                    visible_settings: self.last_persisted.scanner.clone(),
                    saved: false,
                }
            }
        }
    }

    /// Returns the typed update-source value from the current settings snapshot.
    pub const fn current_update_source(&self) -> UpdateSource {
        self.last_persisted.update_source
    }

    /// Returns the update-source value Slint should display for the current snapshot.
    pub fn visible_update_source(&self) -> &'static str {
        self.current_update_source().as_wire_value()
    }

    /// Returns the lowercase log-level value Slint should display for the current snapshot.
    pub fn visible_log_level(&self) -> &'static str {
        log_level_to_ui_value(self.last_persisted.log_level)
    }

    /// Persists an Update Channel radio selection and returns the UI value to show.
    ///
    /// Unknown callback strings are treated as tampered input and the previous
    /// persisted UI value is returned without saving. If saving a known value
    /// fails, the previous snapshot is preserved and returned for UI reversion.
    pub fn select_update_source(&mut self, selected: &str) -> &'static str {
        let Some(update_source) = UpdateSource::from_wire_value(selected) else {
            tracing::error!(
                selected,
                "Settings : Invalid update source selection; reverting"
            );
            return self.visible_update_source();
        };

        let mut candidate = self.last_persisted.clone();
        candidate.update_source = update_source;
        self.save_candidate(candidate, AppSettings::update_source_ui_value)
    }

    /// Persists a Log Level radio selection and returns the lowercase UI value to show.
    ///
    /// Slint emits lowercase values, while the domain model persists uppercase
    /// wire values. Unsupported callback strings are
    /// repaired to `INFO` before saving so tampered UI input cannot persist an
    /// unrepresented radio state.
    pub fn select_log_level(&mut self, selected: &str) -> &'static str {
        let log_level = ui_value_to_log_level(selected).unwrap_or_else(|| {
            tracing::error!(
                selected,
                "Settings : Invalid log level selection; repairing to INFO"
            );
            LogLevel::Info
        });

        let mut candidate = self.last_persisted.clone();
        candidate.log_level = log_level;
        self.save_candidate(candidate, AppSettings::log_level_ui_value)
    }

    fn save_candidate(
        &mut self,
        candidate: AppSettings,
        visible_value: impl FnOnce(&AppSettings) -> &'static str,
    ) -> &'static str {
        let previous_update_source = self.visible_update_source();
        let previous_log_level = self.visible_log_level();

        match self.store.save(&candidate) {
            Ok(()) => {
                self.last_persisted = candidate;
                visible_value(&self.last_persisted)
            }
            Err(error) => {
                tracing::error!(
                    path = %self.store.settings_path().display(),
                    %error,
                    "Settings : Failed to save settings; reverting UI selection"
                );
                // Preserve the pre-save snapshot: callers reset the Slint property to this value.
                match visible_value(&candidate) {
                    "debug" | "info" | "warning" | "error" => previous_log_level,
                    _ => previous_update_source,
                }
            }
        }
    }
}

impl AppSettings {
    fn update_source_ui_value(&self) -> &'static str {
        self.update_source.as_wire_value()
    }

    fn log_level_ui_value(&self) -> &'static str {
        log_level_to_ui_value(self.log_level)
    }
}

fn ui_value_to_log_level(value: &str) -> Option<LogLevel> {
    match value {
        "debug" => Some(LogLevel::Debug),
        "info" => Some(LogLevel::Info),
        "warning" => Some(LogLevel::Warning),
        "error" => Some(LogLevel::Error),
        _ => None,
    }
}

fn log_level_to_ui_value(log_level: LogLevel) -> &'static str {
    match log_level {
        LogLevel::Debug => "debug",
        LogLevel::Info => "info",
        LogLevel::Warning => "warning",
        LogLevel::Error => "error",
    }
}

#[cfg(test)]
mod tests {
    use std::{
        fs,
        path::PathBuf,
        time::{SystemTime, UNIX_EPOCH},
    };

    use crate::{
        app::settings_controller::SettingsController,
        platform::settings_store::{SettingsStore, StaticAssetResolver},
    };

    #[test]
    fn settings_controller_saves_update_source_immediately() {
        let (_root, settings_path) = isolated_settings_path("update-source-save");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(store).expect("controller should load");

        let visible_value = controller.select_update_source("both");

        assert_eq!(visible_value, "both");
        let persisted = fs::read_to_string(settings_path).expect("settings should persist");
        let persisted_json = persisted_json(&persisted);
        assert_eq!(persisted_json["update_source"], "both");
    }

    #[test]
    fn settings_controller_saves_lowercase_log_level_as_uppercase_wire_value() {
        let (_root, settings_path) = isolated_settings_path("log-level-save");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(store).expect("controller should load");

        let visible_value = controller.select_log_level("debug");

        assert_eq!(visible_value, "debug");
        let persisted = fs::read_to_string(settings_path).expect("settings should persist");
        let persisted_json = persisted_json(&persisted);
        assert_eq!(persisted_json["log_level"], "DEBUG");
    }

    #[test]
    fn settings_controller_saves_warning_log_level_as_uppercase_wire_value() {
        let (_root, settings_path) = isolated_settings_path("warning-log-level-save");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(store).expect("controller should load");

        let visible_value = controller.select_log_level("warning");

        assert_eq!(visible_value, "warning");
        let persisted = fs::read_to_string(settings_path).expect("settings should persist");
        let persisted_json = persisted_json(&persisted);
        assert_eq!(persisted_json["log_level"], "WARNING");
    }

    #[test]
    fn settings_controller_preserves_loaded_warning_log_level_until_user_selection() {
        let (_root, settings_path) = isolated_settings_path("warning-preserve");
        fs::write(
            &settings_path,
            r#"{"log_level":"WARNING","update_source":"github"}"#,
        )
        .expect("test fixture should write settings");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );

        let controller =
            SettingsController::load(store).expect("controller should repair settings");

        assert_eq!(controller.visible_log_level(), "warning");
        assert_eq!(controller.visible_update_source(), "github");
        let persisted = fs::read_to_string(settings_path).expect("settings should persist");
        let persisted_json = persisted_json(&persisted);
        assert_eq!(persisted_json["log_level"], "WARNING");
        assert_eq!(persisted_json["update_source"], "github");
    }

    #[test]
    fn settings_controller_reverts_to_last_persisted_value_on_save_failure() {
        let (_root, settings_path) = isolated_settings_path("save-failure-revert");
        let setup_store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(setup_store).expect("controller should load");
        assert_eq!(controller.select_update_source("github"), "github");
        fs::remove_file(&settings_path).expect("settings file should be removable");
        fs::create_dir_all(&settings_path).expect("directory should block future saves");

        let reverted_value = controller.select_update_source("both");

        assert_eq!(reverted_value, "github");
        assert_eq!(controller.visible_update_source(), "github");
    }

    #[test]
    fn settings_controller_reverts_warning_log_level_on_save_failure() {
        let (_root, settings_path) = isolated_settings_path("warning-save-failure-revert");
        let setup_store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(setup_store).expect("controller should load");
        assert_eq!(controller.select_log_level("warning"), "warning");
        fs::remove_file(&settings_path).expect("settings file should be removable");
        fs::create_dir_all(&settings_path).expect("directory should block future saves");

        let reverted_value = controller.select_log_level("debug");

        assert_eq!(reverted_value, "warning");
        assert_eq!(controller.visible_log_level(), "warning");
    }

    #[test]
    fn settings_controller_rejects_invalid_log_level_selection_to_info() {
        let (_root, settings_path) = isolated_settings_path("invalid-log-selection");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(store).expect("controller should load");

        let visible_value = controller.select_log_level("WARNING");

        assert_eq!(visible_value, "info");
        let persisted = fs::read_to_string(settings_path).expect("settings should persist");
        let persisted_json = persisted_json(&persisted);
        assert_eq!(persisted_json["log_level"], "INFO");
    }

    #[test]
    fn settings_controller_saves_scanner_snapshot_for_scan_start() {
        let (_root, settings_path) = isolated_settings_path("scanner-save-on-start");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(store).expect("controller should load");
        let mut scanner = controller.current_scanner_settings().clone();
        scanner.wrong_format = false;
        scanner.race_subgraphs = false;

        let result = controller.save_scanner_settings_for_scan(scanner.clone());

        assert!(result.should_schedule_scan());
        assert_eq!(result.visible_settings, scanner);
        assert_eq!(controller.current_scanner_settings(), &scanner);
        let persisted = fs::read_to_string(settings_path).expect("settings should persist");
        let persisted_json = persisted_json(&persisted);
        assert_eq!(persisted_json["scanner_WrongFormat"], false);
        assert_eq!(persisted_json["scanner_RaceSubgraphs"], false);
    }

    #[test]
    fn settings_controller_saves_scanner_reverts_visible_toggles_on_scan_start_save_failure() {
        let (_root, settings_path) = isolated_settings_path("scanner-save-failure-revert");
        let setup_store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );
        let mut controller = SettingsController::load(setup_store).expect("controller should load");
        let persisted_scanner = controller.current_scanner_settings().clone();
        fs::remove_file(&settings_path).expect("settings file should be removable");
        fs::create_dir_all(&settings_path).expect("directory should block future saves");
        let mut candidate = persisted_scanner.clone();
        candidate.errors = false;
        candidate.junk_files = false;

        let result = controller.save_scanner_settings_for_scan(candidate);

        assert!(!result.should_schedule_scan());
        assert_eq!(result.visible_settings, persisted_scanner);
        assert_eq!(controller.current_scanner_settings(), &persisted_scanner);
    }

    fn isolated_settings_path(case_name: &str) -> (PathBuf, PathBuf) {
        let unique = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("system time should be after Unix epoch")
            .as_nanos();
        let root =
            std::env::temp_dir().join(format!("cmt-rs-settings-controller-{case_name}-{unique}"));
        fs::create_dir_all(&root).expect("test temp directory should be created");
        let settings_path = root.join("settings.json");
        (root, settings_path)
    }

    fn persisted_json(source: &str) -> serde_json::Map<String, serde_json::Value> {
        serde_json::from_str::<serde_json::Value>(source)
            .expect("persisted settings should be JSON")
            .as_object()
            .expect("persisted settings should be a JSON object")
            .clone()
    }
}

